+                    conn,
+                    table_name,
+                    schema,
+                    &sql_col_names,
+                    chunk.len(),
+                )?;
+                let mut flat = Vec::with_capacity(chunk.len() * ncols);
+                for row in chunk {
+                    flat.extend(row.iter().cloned());
+                }
+                conn.insert_rows(&chunk_sql, &[flat])?;
+            }
